+    #[test]
+    fn roundtrip_struct_with_all_field_types() {
+        #[derive(Debug, PartialEq, Serialize, Deserialize)]
+        struct AllTypes {
+            flag: bool,
+            tiny: u8,
+            small: u16,
+            medium: u32,
+            large: u64,
+            signed_tiny: i8,
+            signed_small: i16,
+            signed_medium: i32,
+            signed_large: i64,
+            ratio: f64,
+            label: String,
+            payload: Vec<u8>,
+            maybe: Option<u32>,
+            items: Vec<String>,
+        }
+
+        let schema = SchemaId::new("fcp.test", "AllTypes", Version::new(1, 0, 0));
+        let val = AllTypes {
+            flag: true,
+            tiny: 200,
+            small: 50000,
+            medium: 3_000_000,
+            large: 10_000_000_000,
+            signed_tiny: -100,
+            signed_small: -30000,
+            signed_medium: -2_000_000,
+            signed_large: -5_000_000_000,
+            ratio: 1.23,
+            label: "all types".to_string(),
+            payload: vec![0xDE, 0xAD, 0xBE, 0xEF],
+            maybe: Some(42),
+            items: vec!["one".to_string(), "two".to_string()],
+        };
+
+        let bytes = CanonicalSerializer::serialize(&val, &schema).unwrap();
+        let decoded: AllTypes = CanonicalSerializer::deserialize(&bytes, &schema).unwrap();
+        assert_eq!(decoded, val);
+    }
