+        bytes.extend_from_slice(schema.hash().as_bytes());
+        // Truncated CBOR map
+        bytes.extend_from_slice(&[0xA2, 0x61, b'a']);
+        let result =
+            CanonicalSerializer::deserialize_unchecked::<HashMap<String, u8>>(&bytes, &schema);
+        assert!(result.is_err());
+    }
